// src/app/ms102-test/data/questions.ts

export type Ms102Question = {
  /** ID aus deiner Sammlung (z.B. Q11, q64, Q344, …) */
  id: string;
  /** Laufende Nummer im Test (1–110 gedacht, hier aktuell 1–25) */
  number: number;
  /** Themenbereich laut MS-102 Blueprint */
  area: string;
  /** grobe Schwierigkeit zur Orientierung */
  difficulty: "easy" | "medium" | "hard";
  /**
   * Fragetext.
   * WICHTIG: In der React-Komponente mit className="whitespace-pre-line"
   * oder style={{ whiteSpace: "pre-line" }} rendern,
   * damit Zeilenumbrüche & Listen sichtbar sind.
   */
  question: string;
  /** Antwortoptionen A, B, C, … */
  options: { key: string; text: string }[];
  /** Richtige(n) Antwort(en), z.B. ["B"] oder ["B", "D"] */
  correctAnswers: string[];
  /** Deutsche Erklärung, warum die Antwort richtig ist (prüfungsrelevant erklärt) */
  explanationDe: string;
  /** Optionale Links zu Docs / Referenzen */
  references?: string[];
};

